queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?servicename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasServices ?child ; p:hasGates ?parent . } GROUP BY ?child }
  ?child p:serviceName ?servicename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Gates } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?gatenumber ?servicename WHERE {
  ?gates_services a :Gates_Services .
  ?services a :Services .
  ?gates_services p:hasServices ?services .
  ?gates a :Gates .
  ?gates_services p:hasGates ?gates .
  ?gates p:gateNumber ?gatenumber .
  ?services p:serviceName ?servicename .
} }
  collective: { SELECT ?servicename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasServices ?child ; p:hasGates ?parent . } GROUP BY ?child }
  ?child p:serviceName ?servicename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Gates } }
  FILTER(?nf = ?total)
} }
}
